"use strict";parserFactory.register("jadescrolls.com",()=>new JadeScrollsParser);class JadeScrollsParser extends Parser{constructor(){super(),this.ChacheChapterContent=new Map}populateUIImpl(){document.getElementById("removeChapterNumberRow").hidden=!1}async getChapterUrls(){let t=[],e=(await HttpClient.fetchJson("https://api.jadescrolls.com/api/novels-chapter/"+this.id+"/chapters/list?limit="+this.chapters_count+"&page=1&novelId="+this.id+"&status=PUBLISHED&isDeleted=false&sortOrder=desc")).json;return t=this.chaptersFromJson(e),this.chacheChapter(e),t}chaptersFromJson(t){return t.data.map(t=>({sourceUrl:"https://jadescrolls.com/novel/"+this.slug+"/"+t.slug,title:document.getElementById("removeChapterNumberCheckbox").checked?t.title:"Chapter "+t.chapter_number+": "+t.title,isIncludeable:"FREE"==t.type})).reverse()}chacheChapter(t){t.data.map(t=>this.ChacheChapterContent.set("https://jadescrolls.com/novel/"+this.slug+"/"+t.slug,[t.title,t.content]))}async loadEpubMetaInfo(t){let e=new URL(t.baseURI).pathname.match(/\/novel\/([^/]+)/),s=e?e[1]:null;if(!s)throw new Error(`Could not extract JadeScrolls novel slug from URL: ${t.baseURI}\nExpected a URL like jadescrolls.com/novel/novel-slug`);let r=(await HttpClient.fetchJson("https://api.jadescrolls.com/api/novels?slug="+s)).json;this.title=r.title,this.author=r.author_name,this.description=r.synopsis,this.img=r.cover_image,this.tags="";for(let t in r?.genres)this.tags=this.tags.concat(t?.name);for(let t in r?.sub_genres)this.tags=this.tags.concat(t?.name);this.novelSlug=s,this.id=r.id,this.chapters_count=r.chapters_count}findContent(t){return Parser.findConstrutedContent(t)}extractTitleImpl(){return this.title}extractAuthor(){return this.author}extractSubject(){return this.tags.join(", ")}extractDescription(){return this.description.trim()}findCoverImageUrl(){return this.img}async fetchChapter(t){if(this.ChacheChapterContent.has(t))return this.minimumThrottle=0,this.buildChapterfromChache(this.ChacheChapterContent.get(t),t);{this.minimumThrottle=this.getRateLimit();let e=this.toRestUrl(t),s=(await HttpClient.fetchJson(e)).json;return this.buildChapter(s,t)}}buildChapterfromChache(t,e){let s=Parser.makeEmptyDocForContent(e),r=s.dom.createElement("h1");r.textContent=t[0],s.content.appendChild(r);let n=util.sanitize(t[1]);return util.moveChildElements(n.body,s.content),s.dom}toRestUrl(t){let e=t.split("/");return"https://api.jadescrolls.com/api/novels-chapter/"+e[e.length-2]+"/chapters/"+e[e.length-1]}buildChapter(t,e){let s=Parser.makeEmptyDocForContent(e),r=s.dom.createElement("h1");r.textContent=t?.title,s.content.appendChild(r);let n=util.sanitize(t?.content);return util.moveChildElements(n.body,s.content),s.dom}}